import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsEscapeCharacterSet() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertFalse(result);
    }

    @Test
    public void testIsEscapeCharacterSetWithEscapeCharacter() {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withEscape('\\');

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertTrue(result);
    }

    @Test
    public void testIsEscapeCharacterSetWithEscapeCharacterNull() {
        // Given
        CSVFormat csvFormat = CSVFormat.newFormat(',').withEscape(null);

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertFalse(result);
    }
}
